UPDATE `custom_settings` SET `value` = '[\r\n	{\r\n		\"fields\": [\r\n			{\r\n				\"type\": \"date\",\r\n				\"name\": \"call_date\"\r\n			}\r\n		],\r\n		\"object_name\": \"call\"\r\n	},\r\n	{\r\n		\"fields\": [\r\n			{\r\n				\"type\": \"date\",\r\n				\"name\": \"coaching_date\"\r\n			}\r\n		],\r\n		\"object_name\": \"coaching\"\r\n	},\r\n	{\r\n		\"fields\": [\r\n			{\r\n				\"type\": \"datetime\",\r\n				\"name\": \"event_start_time\",\r\n				\"time_tag\": \"start\"\r\n			},\r\n			{\r\n				\"type\": \"datetime\",\r\n				\"name\": \"event_end_time\",\r\n				\"time_tag\": \"end\"\r\n			}\r\n		],\r\n		\"record_type_config\": {\r\n			\"cs_patient_education_meeting\": {\r\n				\"fields_for_agenda\": [],\r\n				\"fields_for_plan\": [\r\n					{\r\n						\"type\": \"datetime\",\r\n						\"name\": \"event_start_time\",\r\n						\"time_tag\": \"start\"\r\n					},\r\n					{\r\n						\"type\": \"datetime\",\r\n						\"name\": \"end_time\",\r\n						\"time_tag\": \"end\"\r\n					}\r\n				]\r\n			},\r\n			\"cs_department\": {\r\n				\"fields_for_agenda\": []\r\n			}\r\n		},\r\n		\"object_name\": \"event\"\r\n	},\r\n	{\r\n		\"fields\": [\r\n			{\r\n				\"type\": \"datetime\",\r\n				\"name\": \"start_time\",\r\n				\"time_tag\": \"start\"\r\n			},\r\n			{\r\n				\"type\": \"datetime\",\r\n				\"name\": \"end_time\",\r\n				\"time_tag\": \"end\"\r\n			}\r\n		],\r\n		\"record_type_config\": {\r\n			\"weekly_plan_call_plans\": {\r\n				\"fields_for_agenda\": [],\r\n				\"fields_for_plan\": [\r\n					{\r\n						\"type\": \"datetime\",\r\n						\"name\": \"start_time\",\r\n						\"time_tag\": \"start\"\r\n					},\r\n					{\r\n						\"type\": \"datetime\",\r\n						\"name\": \"end_time\",\r\n						\"time_tag\": \"end\"\r\n					}\r\n				]\r\n			 },\r\n			\"weekly_plan_coaching_plans\": {\r\n				\"fields_for_agenda\": [],\r\n				\"fields_for_plan\": [\r\n					{\r\n						\"type\": \"datetime\",\r\n						\"name\": \"start_time\",\r\n						\"time_tag\": \"start\"\r\n					},\r\n					{\r\n						\"type\": \"datetime\",\r\n						\"name\": \"end_time\",\r\n						\"time_tag\": \"end\"\r\n					}\r\n				]\r\n			 }\r\n			},\r\n		\"object_name\": \"weekly_plan\"\r\n	},\r\n	{\r\n		\"fields\": [\r\n			{\r\n				\"type\": \"date\",\r\n				\"name\": \"date\"\r\n			}\r\n		],\r\n		\"object_name\": \"time_off_territory\"\r\n	}\r\n]' WHERE `key` = 'calendar_create_data_config';


